SELECT status, COUNT(*) as count
FROM content_drafts
WHERE created_by = #{userId} AND del_flag = 0

    AND create_time  >  #{startDate}


    AND create_time <= #{endDate}

GROUP BY status

SELECT status, COUNT(*) as count
FROM content_drafts
WHERE del_flag = 0

    AND create_time  >  #{startDate}


    AND create_time <= #{endDate}

GROUP BY status

SELECT content_type, COUNT(*) as count
FROM content_drafts
WHERE created_by = #{userId} AND del_flag = 0

    AND create_time  >  #{startDate}


    AND create_time <= #{endDate}

GROUP BY content_type

SELECT content_type, COUNT(*) as count
FROM content_drafts
WHERE del_flag = 0

    AND create_time  >  #{startDate}


    AND create_time <= #{endDate}

GROUP BY content_type

SELECT DATE(create_time) as date, COUNT(*) as count FROM content_drafts WHERE created_by = #{userId} AND del_flag = 0
AND create_time > #{startDate}
AND create_time <= #{endDate}
GROUP BY DATE(create_time) ORDER BY DATE(create_time)

SELECT DATE(create_time) as date, COUNT(*) as count FROM content_drafts WHERE del_flag = 0
AND create_time > #{startDate}
AND create_time <= #{endDate}
GROUP BY DATE(create_time) ORDER BY DATE(create_time)

SELECT DATE(publish_time) as date, COUNT(*) as count FROM content_drafts WHERE created_by = #{userId} AND del_flag = 0 AND publish_time IS NOT NULL
AND publish_time > #{startDate}
AND publish_time <= #{endDate}
GROUP BY DATE(publish_time) ORDER BY DATE(publish_time)

SELECT DATE(publish_time) as date, COUNT(*) as count FROM content_drafts WHERE del_flag = 0 AND publish_time IS NOT NULL
AND publish_time > #{startDate}
AND publish_time <= #{endDate}
GROUP BY DATE(publish_time) ORDER BY DATE(publish_time)

SELECT AVG(word_count) as avg_word_count
FROM content_drafts
WHERE created_by = #{userId} AND del_flag = 0 AND word_count IS NOT NULL

    AND create_time  >  #{startDate}


    AND create_time <= #{endDate}

SELECT AVG(word_count) as avg_word_count
FROM content_drafts
WHERE del_flag = 0 AND word_count IS NOT NULL

    AND create_time  >  #{startDate}


    AND create_time <= #{endDate}

SELECT AVG(reading_time) as avg_reading_time
FROM content_drafts
WHERE created_by = #{userId} AND del_flag = 0 AND reading_time IS NOT NULL

    AND create_time  >  #{startDate}


    AND create_time <= #{endDate}

SELECT AVG(reading_time) as avg_reading_time
FROM content_drafts
WHERE del_flag = 0 AND reading_time IS NOT NULL

    AND create_time  >  #{startDate}


    AND create_time <= #{endDate}

SELECT created_by as user_id, COUNT(*) as draft_count, COUNT(CASE WHEN status = 'published' THEN 1 END) as publish_count, MAX(update_time) as last_active_time FROM content_drafts WHERE del_flag = 0
AND create_time > #{startDate}
AND create_time <= #{endDate}
GROUP BY created_by ORDER BY draft_count DESC, publish_count DESC LIMIT #{limit}

SELECT content_type,
       COUNT(*) as draft_count,
       COUNT(CASE WHEN status = 'published' THEN 1 END) as publish_count
FROM content_drafts
WHERE del_flag = 0 AND content_type IS NOT NULL

    AND create_time  >  #{startDate}


    AND create_time <= #{endDate}

GROUP BY content_type
ORDER BY draft_count DESC, publish_count DESC
LIMIT #{limit}

SELECT * FROM content_drafts
WHERE status = 'scheduled'
  AND scheduled_date <= #{currentTime}
  AND del_flag = 0
ORDER BY scheduled_date ASC
LIMIT #{limit}

SELECT * FROM content_drafts
WHERE del_flag = 1
  AND update_time < #{expireDate}
ORDER BY update_time ASC
LIMIT #{limit}
